package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.bind.ReflectiveTypeAdapterFactory;
import com.google.gson.internal.Excluder;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class ReflectiveTypeAdapterFactoryTest {

  @Mock
  private Excluder excluderMock;

  private ReflectiveTypeAdapterFactory factory;

  @BeforeEach
  void setUp() {
    MockitoAnnotations.openMocks(this);
    // Other constructor args can be null since they are not used in includeField
    factory = new ReflectiveTypeAdapterFactory(null, null, excluderMock, null, null);
  }

  private boolean invokeIncludeField(Field field, boolean serialize) throws Exception {
    var method = ReflectiveTypeAdapterFactory.class.getDeclaredMethod("includeField", Field.class, boolean.class);
    method.setAccessible(true);
    return (boolean) method.invoke(factory, field, serialize);
  }

  static class TestClass {
    public int includedField;
    public static int staticField;
  }

  @Test
  void includeField_shouldReturnFalse_whenExcludeClassIsTrue() throws Exception {
    Field field = TestClass.class.getField("includedField");
    when(excluderMock.excludeClass(field.getType(), true)).thenReturn(true);

    boolean result = invokeIncludeField(field, true);

    assertFalse(result);
    verify(excluderMock).excludeClass(field.getType(), true);
    verify(excluderMock, never()).excludeField(any(), anyBoolean());
  }

  @Test
  void includeField_shouldReturnFalse_whenExcludeFieldIsTrue_andExcludeClassIsFalse() throws Exception {
    Field field = TestClass.class.getField("includedField");
    when(excluderMock.excludeClass(field.getType(), false)).thenReturn(false);
    when(excluderMock.excludeField(field, false)).thenReturn(true);

    boolean result = invokeIncludeField(field, false);

    assertFalse(result);
    verify(excluderMock).excludeClass(field.getType(), false);
    verify(excluderMock).excludeField(field, false);
  }

  @Test
  void includeField_shouldReturnTrue_whenNeitherExcludeClassNorExcludeField() throws Exception {
    Field field = TestClass.class.getField("includedField");
    when(excluderMock.excludeClass(field.getType(), true)).thenReturn(false);
    when(excluderMock.excludeField(field, true)).thenReturn(false);

    boolean result = invokeIncludeField(field, true);

    assertTrue(result);
    verify(excluderMock).excludeClass(field.getType(), true);
    verify(excluderMock).excludeField(field, true);
  }

  @Test
  void includeField_shouldWorkWithStaticField() throws Exception {
    Field field = TestClass.class.getField("staticField");
    when(excluderMock.excludeClass(field.getType(), false)).thenReturn(false);
    when(excluderMock.excludeField(field, false)).thenReturn(false);

    boolean result = invokeIncludeField(field, false);

    assertTrue(result);
    verify(excluderMock).excludeClass(field.getType(), false);
    verify(excluderMock).excludeField(field, false);
  }
}
